import base64, os

base = os.path.expanduser('~/Desktop/amway-manager')

files = {
    'App.jsx': '',
    'Sidebar.jsx': '',
    'Accounts.jsx': '',
}

dest = {
    'App.jsx':      base + '/src/App.jsx',
    'Sidebar.jsx':  base + '/src/components/Sidebar.jsx',
    'Accounts.jsx': base + '/src/components/Accounts.jsx',
}

for name, data in files.items():
    with open(dest[name], 'wb') as f:
        f.write(base64.b64decode(data))
    print('✅ ' + name)

print('\n¡Listo! Los 3 archivos instalados.')
